export function createHandler(getIncomingHeaders: GetHeaders) {
  return http.all('*', async ({ request }) => {
    const mockSchemas = await extractMockSchemas(getIncomingHeaders);
    const matchResult = await matchSchemas(request, mockSchemas);
    if (!matchResult) return;
    // ...
  });
}
```

Key point: `if (!matchResult) return;` — when there's no match, the handler returns `undefined`. 

In MSW, returning `undefined` from a handler means "don't mock this request" and it passes through to the actual network. But here's the critical issue: the RMP handler matches every request with `http.all('*')`, so it always intercepts them. When there's no schema match, it returns `undefined`, which tells MSW "I'm not handling this" — but MSW still considers the request handled by that handler, so the `onUnhandledRequest` callback never fires.

